# Bucle for básico
for i in range(5):
    print("Iteración:", i)

# range(inicio, fin)
for i in range(1, 6):
    print("Número:", i)

# range(inicio, fin, paso)
for i in range(0, 10, 2):
    print(i, "es par")

# break - salir del bucle
for i in range(10):
    if i == 5:
        print("¡Encontré el 5, salgo!")
        break
    print("i =", i)

print("Bucle terminado")

# continue - saltar iteración
for i in range(5):
    if i == 2:
        continue  # Saltar el 2
    print("i =", i)

print("Fin")

