# try-except-else-finally
def dividir_seguro(a, b):
    try:
        resultado = a / b
    except ZeroDivisionError:
        return "Error: división por cero"
    else:
        print("División exitosa")
        return resultado
    finally:
        print("Esta línea siempre se ejecuta")

print(dividir_seguro(10, 2))

