# Usando diccionario para operaciones
operaciones = {
    "1": ("sumar", lambda a, b: a + b),
    "2": ("restar", lambda a, b: a - b),
    "3": ("multiplicar", lambda a, b: a * b),
    "4": ("dividir", lambda a, b: a / b if b != 0 else None)
}

def usar_calculadora():
    opcion = input("Elige (1-4): ")
    if opcion in operaciones:
        nombre, func = operaciones[opcion]
        try:
            a = float(input("a: "))
            b = float(input("b: "))
            resultado = func(a, b)
            print(f"{nombre}: {resultado}")
        except:
            print("Error en la operación")
    else:
        print("Opción inválida")

